  "inlineSchema": "generator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"debian-openssl-3.0.x\", \"windows\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// --- GEOGRAPHY (MODERN HIERARCHY) ---\n\nmodel Loksabha {\n  id           Int           @id @default(autoincrement())\n  name         String        @unique\n  vidhansabhas Vidhansabha[]\n}\n\nmodel Vidhansabha {\n  id         Int         @id @default(autoincrement())\n  name       String\n  loksabhaId Int\n  loksabha   Loksabha    @relation(fields: [loksabhaId], references: [id])\n  localUnits LocalUnit[]\n  elections  Election[]\n\n  @@unique([loksabhaId, name])\n  @@index([loksabhaId])\n}\n\nmodel LocalUnit {\n  id            Int           @id @default(autoincrement())\n  vidhansabhaId Int\n  name          String\n  type          LocalUnitType\n  vidhansabha   Vidhansabha   @relation(fields: [vidhansabhaId], references: [id])\n\n  users      User[]\n  committees Committee[]\n\n  // Ensures you can't have \"Ward 1\" twice in the same Vidhansabha\n  @@unique([vidhansabhaId, name, type])\n  @@index([vidhansabhaId, type])\n}\n\n// --- REMOVED LEGACY TABLES (District, GramPanchayat, Ward) ---\n\n// --- USERS & AUTH ---\n\nmodel User {\n  id       Int     @id @default(autoincrement())\n  name     String\n  phone    String  @unique\n  password String // Renamed from passwordHash to match seed script\n  address  String? // Made optional for flexibility\n\n  // Role Management\n  role Role @default(Member) // Default is now 'Member'\n\n  // IDs & Links\n  authUserId String? @unique // Supabase UUID\n  memberId   String? @unique // PGP-123456\n  photoUrl   String?\n\n  // Location Link (Strictly LocalUnit now)\n  localUnitId Int?\n  localUnit   LocalUnit? @relation(fields: [localUnitId], references: [id])\n\n  // Referral System\n  referralCode     String? @unique // Made optional, generated on signup\n  referredByUserId Int?\n  referredBy       User?   @relation(\"UserReferrals\", fields: [referredByUserId], references: [id])\n  recruits         User[]  @relation(\"UserReferrals\")\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  auditLogs            AuditLog[]         @relation(\"AuditActor\")\n  ballotSubmissions    BallotSubmission[]\n  candidates           Candidate[]\n  committeeMemberships CommitteeMember[]\n  receivedVotes        Vote[]             @relation(\"CandidateVotes\")\n  votes                Vote[]             @relation(\"UserVotes\")\n\n  @@index([referredByUserId])\n  @@index([role])\n  @@index([localUnitId])\n}\n\n// --- ELECTIONS ---\n\nmodel Election {\n  id           Int            @id @default(autoincrement())\n  councilLevel CouncilLevel\n  position     String         @default(\"President\")\n  status       ElectionStatus @default(Active)\n\n  // Geo-fencing elections\n  vidhansabhaId Int?\n  vidhansabha   Vidhansabha? @relation(fields: [vidhansabhaId], references: [id])\n\n  openedAt  DateTime? @default(now())\n  closedAt  DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  ballotSubmissions BallotSubmission[]\n  candidates        Candidate[]\n  votes             Vote[]\n\n  @@index([vidhansabhaId])\n}\n\nmodel Candidate {\n  id         Int      @id @default(autoincrement())\n  electionId Int\n  userId     Int\n  election   Election @relation(fields: [electionId], references: [id])\n  user       User     @relation(fields: [userId], references: [id])\n\n  @@unique([electionId, userId])\n}\n\nmodel Vote {\n  id              Int      @id @default(autoincrement())\n  electionId      Int\n  voterUserId     Int\n  candidateUserId Int\n  createdAt       DateTime @default(now())\n\n  election  Election @relation(fields: [electionId], references: [id])\n  voter     User     @relation(\"UserVotes\", fields: [voterUserId], references: [id])\n  candidate User     @relation(\"CandidateVotes\", fields: [candidateUserId], references: [id])\n\n  @@unique([electionId, voterUserId, candidateUserId]) // Prevents double voting for same person\n}\n\nmodel BallotSubmission {\n  id          Int      @id @default(autoincrement())\n  electionId  Int\n  voterUserId Int\n  createdAt   DateTime @default(now())\n\n  election Election @relation(fields: [electionId], references: [id])\n  voter    User     @relation(fields: [voterUserId], references: [id])\n\n  @@unique([electionId, voterUserId]) // Ensures 1 ballot per election per user\n}\n\n// --- COMMITTEES ---\n\nmodel Committee {\n  id          Int               @id @default(autoincrement())\n  name        String\n  type        CommitteeType\n  localUnitId Int\n  localUnit   LocalUnit         @relation(fields: [localUnitId], references: [id])\n  members     CommitteeMember[]\n\n  @@unique([name, localUnitId, type])\n  @@index([localUnitId])\n}\n\nmodel CommitteeMember {\n  userId      Int\n  committeeId Int\n  role        Role?\n  isPresident Boolean  @default(false)\n  createdAt   DateTime @default(now())\n\n  committee Committee @relation(fields: [committeeId], references: [id])\n  user      User      @relation(fields: [userId], references: [id])\n\n  @@id([userId, committeeId])\n  @@index([committeeId])\n}\n\n// --- AUDIT ---\n\nmodel AuditLog {\n  id          Int      @id @default(autoincrement())\n  actorUserId Int?\n  action      String\n  entityType  String\n  entityId    String\n  reason      String?\n  metadata    Json?\n  createdAt   DateTime @default(now())\n\n  actor User? @relation(\"AuditActor\", fields: [actorUserId], references: [id])\n\n  @@index([actorUserId])\n}\n\n// --- ENUMS ---\n\nenum Role {\n  Admin\n  Member // The default base role\n  CWCMember\n  CWCPresident\n  APC // Assembly Level Council\n  PPC // Parliament Level\n  SSP // State Level\n  ALCPresident // Assembly President\n  SLCPresident // State President\n}\n\nenum CouncilLevel {\n  CWC\n  APC\n  ALC\n  SLC\n}\n\nenum ElectionStatus {\n  Active\n  Closed\n}\n\nenum LocalUnitType {\n  Ward\n  GramPanchayat\n}\n\nenum CommitteeType {\n  CWC\n  APC\n  PPC\n  SSP\n}\n",
